const body = $input.first().json.body || $input.first().json;
const text = (body.text || '').toString();
const chatId = String(body.chat_id || '');
const isTest = chatId === 'test' || chatId.startsWith('test-');
return [{ json: { text, chat_id: chatId, is_test: isTest } }];

const ctx = $('Extract Context').first().json;
const healthResp = $('N8N Health').first().json || {};
const stateResp = $input.first().json;
const status = healthResp.statusCode || healthResp.status || 0;
const healthy = status >= 200 && status < 300;
const lines = [];
lines.push(healthy ? '\u2705 N8N \u05d1\u05e8\u05d9\u05d0 (healthz 200)' : '\u26a0\ufe0f N8N \u05dc\u05d0 \u05de\u05d2\u05d9\u05d1 (' + status + ')');
let state = null;
try {
  state = (stateResp && typeof stateResp === 'object') ? stateResp : JSON.parse(String(stateResp));
} catch (e) {}
const stages = (state && Array.isArray(state.build_stages)) ? state.build_stages : null;
if (stages && stages.length > 0) {
  const VERB = { completed: '\u05d4\u05d5\u05e9\u05dc\u05dd', in_progress: '\u05d1\u05e2\u05d1\u05d5\u05d3\u05d4', pending: '\u05de\u05de\u05ea\u05d9\u05df' };
  const current = stages.find(s => s.status === 'in_progress')
    || stages.find(s => s.status === 'pending')
    || [...stages].reverse().find(s => s.status === 'completed');
  lines.push('\u05e9\u05dc\u05d1 ' + current.number + ': ' + current.name + ' \u2014 ' + (VERB[current.status] || VERB.pending));
  const prs = Array.isArray(state.open_prs) ? state.open_prs : [];
  lines.push('PRs \u05e4\u05ea\u05d5\u05d7\u05d9\u05dd: ' + prs.length);
} else {
  lines.push('\u26a0\ufe0f \u05dc\u05d0 \u05e0\u05d9\u05ea\u05df \u05dc\u05e7\u05e8\u05d5\u05d0 state.json');
}
const reply = lines.join('\n');
return [{ json: { chat_id: ctx.chat_id, reply_text: reply, is_test: ctx.is_test } }];
